// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { 
  getOverview, getUsers, getRiders, getApprovedCaptains, 
  getPendingCaptains, getRides, approveCaptain, rejectCaptain 
} from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import { 
  Box, Typography, Button, CircularProgress, Table, TableHead, TableRow, TableCell, TableBody, Card, CardContent, Grid 
} from "@mui/material";

// Icons
import PeopleIcon from '@mui/icons-material/People';
import PersonIcon from '@mui/icons-material/Person';
import EmailIcon from '@mui/icons-material/Email';
import PhoneIcon from '@mui/icons-material/Phone';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CancelIcon from '@mui/icons-material/Cancel';
import ThumbUpIcon from '@mui/icons-material/ThumbUp';
import ThumbDownIcon from '@mui/icons-material/ThumbDown';
import LocalTaxiIcon from '@mui/icons-material/LocalTaxi';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [overview, setOverview] = useState({});
  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchOverview();
  }, []);

  const fetchOverview = async () => {
    setLoading(true);
    setError("");
    try {
      const res = await getOverview();
      setOverview(res.data);
    } catch (err) {
      console.error("Overview fetch error:", err);
      setError("Failed to load overview");
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch(type){
        case "users": res = await getUsers(); break;
        case "riders": res = await getRiders(); break;
        case "captains": res = await getApprovedCaptains(); break;
        case "pending": res = await getPendingCaptains(); break;
        case "rides": res = await getRides(); break;
        default: res = { data: [] };
      }

      const listMap = {
        users: res?.data?.users || [],
        riders: res?.data?.riders || [],
        captains: res?.data?.captains || [],
        pending: res?.data?.pendingCaptains || [],
        rides: res?.data?.rides || [],
      };

      setData(listMap[type]);
    } catch (err) {
      console.error("Data fetch error:", err);
      setError("Failed to fetch data");
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch {
      setError("Failed to approve captain");
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch {
      setError("Failed to reject captain");
    }
  };

  return (
    <Box p={2}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={logout}>Logout</Button>
      </Box>

      {/* Overview Cards */}
      <Grid container spacing={2} mb={3}>
        <Grid item xs={12} sm={6} md={2}>
          <Card sx={{ textAlign: "center", p: 2 }}>
            <PeopleIcon fontSize="large" color="primary"/>
            <Typography variant="h6">{overview.users || 0}</Typography>
            <Typography>Users</Typography>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card sx={{ textAlign: "center", p: 2 }}>
            <PersonIcon fontSize="large" color="secondary"/>
            <Typography variant="h6">{overview.riders || 0}</Typography>
            <Typography>Riders</Typography>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card sx={{ textAlign: "center", p: 2 }}>
            <VerifiedUserIcon fontSize="large" color="success"/>
            <Typography variant="h6">{overview.captains || 0}</Typography>
            <Typography>Approved Captains</Typography>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card sx={{ textAlign: "center", p: 2 }}>
            <PendingActionsIcon fontSize="large" color="warning"/>
            <Typography variant="h6">{overview.pendingCaptains || 0}</Typography>
            <Typography>Pending Captains</Typography>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card sx={{ textAlign: "center", p: 2 }}>
            <LocalTaxiIcon fontSize="large" color="info"/>
            <Typography variant="h6">{overview.rides || 0}</Typography>
            <Typography>Rides</Typography>
          </Card>
        </Grid>
      </Grid>

      {/* Tabs Buttons */}
      <Box mb={2} display="flex" gap={1}>
        <Button variant="outlined" onClick={() => fetchData("users")}>Users</Button>
        <Button variant="outlined" onClick={() => fetchData("riders")}>Riders</Button>
        <Button variant="outlined" onClick={() => fetchData("captains")}>Approved Captains</Button>
        <Button variant="outlined" onClick={() => fetchData("pending")}>Pending Captains</Button>
        <Button variant="outlined" onClick={() => fetchData("rides")}>Rides</Button>
      </Box>

      {loading && <CircularProgress />}
      {error && <Typography color="error">{error}</Typography>}

      {!loading && data.length > 0 && (
        <Table>
          <TableHead>
            <TableRow>
              <TableCell><PersonIcon /> Name</TableCell>
              <TableCell><EmailIcon /> Email</TableCell>
              <TableCell><PhoneIcon /> Mobile</TableCell>
              <TableCell><VerifiedUserIcon /> Role</TableCell>
              <TableCell><CheckCircleIcon /> Approval</TableCell>
              {activeTab === "pending" && <TableCell>Actions</TableCell>}
              {activeTab === "rides" && <>
                <TableCell>Pickup</TableCell>
                <TableCell>Drop</TableCell>
                <TableCell>Status</TableCell>
              </>}
            </TableRow>
          </TableHead>
          <TableBody>
            {data.map(item => (
              <TableRow key={item._id}>
                <TableCell>{item.fullName || "-"}</TableCell>
                <TableCell>{item.email || "-"}</TableCell>
                <TableCell>{item.mobile || "-"}</TableCell>
                <TableCell>{item.role || "-"}</TableCell>
                <TableCell>
                  {item.approvalStatus === "approved" ? <CheckCircleIcon color="success"/> :
                   item.approvalStatus === "rejected" ? <CancelIcon color="error"/> : "-"}
                </TableCell>
                {activeTab === "pending" && <TableCell>
                  <Button size="small" color="success" onClick={() => handleApprove(item._id)} startIcon={<ThumbUpIcon />}>Approve</Button>
                  <Button size="small" color="error" onClick={() => handleReject(item._id)} startIcon={<ThumbDownIcon />}>Reject</Button>
                </TableCell>}
                {activeTab === "rides" && <>
                  <TableCell>{item.pickup}</TableCell>
                  <TableCell>{item.drop}</TableCell>
                  <TableCell>{item.status}</TableCell>
                </>}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {!loading && data.length === 0 && <Typography>No data found</Typography>}
    </Box>
  );
}
